// Validate input shape — fail fast if required fields missing.
// Input is a single object: { consignment: {...}, items: [{...}] }

const input = $input.first().json;

if (!input || typeof input !== 'object') {
  throw new Error('Input must be a JSON object with `consignment` and `items` keys');
}

const { consignment, items } = input;

if (!consignment || typeof consignment !== 'object') {
  throw new Error('Missing required field: `consignment` (object)');
}

for (const k of ['shipper', 'consignee', 'transport_mode', 'origin_country', 'destination_country']) {
  if (!consignment[k]) {
    throw new Error(`consignment.${k} is required`);
  }
}

if (!Array.isArray(items) || items.length === 0) {
  throw new Error('`items` must be a non-empty array');
}

const REQUIRED_ITEM_FIELDS = ['un_number', 'quantity_per_package', 'quantity_unit', 'package_count', 'packaging_type'];
const VALID_UNITS = ['L', 'kg', 'mL', 'g'];
const VALID_PACKAGING = ['drums', 'IBC', 'jerricans', 'boxes', 'bags', 'other'];

for (let i = 0; i < items.length; i++) {
  const it = items[i];
  for (const k of REQUIRED_ITEM_FIELDS) {
    if (it[k] === undefined || it[k] === null || it[k] === '') {
      throw new Error(`items[${i}].${k} is required`);
    }
  }
  if (!VALID_UNITS.includes(it.quantity_unit)) {
    throw new Error(`items[${i}].quantity_unit must be one of ${VALID_UNITS.join(', ')}`);
  }
  if (!VALID_PACKAGING.includes(it.packaging_type)) {
    throw new Error(`items[${i}].packaging_type must be one of ${VALID_PACKAGING.join(', ')}`);
  }
  if (typeof it.package_count !== 'number' || it.package_count <= 0 || !Number.isInteger(it.package_count)) {
    throw new Error(`items[${i}].package_count must be a positive integer`);
  }
  if (typeof it.quantity_per_package !== 'number' || it.quantity_per_package <= 0) {
    throw new Error(`items[${i}].quantity_per_package must be a positive number`);
  }
}

// Compute total_quantity per item for downstream API calls.
const itemsWithTotal = items.map((it) => ({
  ...it,
  total_quantity: it.quantity_per_package * it.package_count,
}));

return [
  {
    json: {
      consignment,
      items: itemsWithTotal,
    },
  },
];

// Per-item: pick the variant_index 0 of the adr_lookup result and merge
// it into the original item shape so downstream nodes have one flat record
// per item.
//
// $('Split Items').item gives the upstream split item (which carries the
// original `un_number`, `quantity_per_package`, etc.). $input.first().json
// is the adr_lookup response { count, results, meta }.

const lookup = $input.first().json;
const originalItem = $('Split Items').item.json;

const variant = (lookup.results && lookup.results[0]) ? lookup.results[0] : null;

if (!variant) {
  // Unknown UN — emit a warning record so downstream Compose can flag it.
  return [{
    json: {
      ...originalItem,
      adr_data: null,
      adr_lookup_error: `UN ${originalItem.un_number} not found in ADR 2025 dataset`,
    },
  }];
}

return [{
  json: {
    ...originalItem,
    adr_data: {
      un_number: variant.un_number,
      proper_shipping_name: variant.proper_shipping_name,
      class: variant.class,
      classification_code: variant.classification_code,
      packing_group: variant.packing_group,
      labels: variant.labels,
      special_provisions: variant.special_provisions,
      limited_quantity: variant.limited_quantity,
      excepted_quantity: variant.excepted_quantity,
      transport_category: variant.transport_category,
      tunnel_restriction_code: variant.tunnel_restriction_code,
      hazard_identification_number: variant.hazard_identification_number,
      variant_index: variant.variant_index,
    },
  },
}];

