// Compose final output by joining: consignment header + per-item enriched
// data + consignment-level lq + consignment-level exemption.

const aggregated = $('Aggregate Items').first().json.data; // enriched items
const lqResp = $('ADR LQ Check (Consignment)').first().json;
const exemptionResp = $input.first().json; // exemption is the immediate predecessor
const consignment = $('Validate Input').first().json.consignment;

// Build per-item records
const lqByUn = new Map();
for (const li of (lqResp.items || [])) {
  if (!lqByUn.has(li.un_number)) lqByUn.set(li.un_number, []);
  lqByUn.get(li.un_number).push(li);
}

// Tunnel restriction ordering: '-' < A < B < C < D < E. Empty string treated as '-'.
function tunnelRank(code) {
  if (!code) return 0;
  const c = code.replace(/[()]/g, '').toUpperCase();
  if (c === '-' || c === '') return 0;
  // Codes can be like 'D/E', 'B/D', take the most restrictive letter
  const letters = c.split(/[\/]/).map((s) => s.trim()).filter(Boolean);
  let max = 0;
  for (const l of letters) {
    const r = l.charCodeAt(0) - 'A'.charCodeAt(0) + 1; // A=1 ... E=5
    if (r > max) max = r;
  }
  return max;
}

const itemsOut = aggregated.map((it, idx) => {
  // pick the matching lq entry — if same UN appears multiple times, take the first lq match per item index in order
  const matches = lqByUn.get(it.un_number) ?? [];
  const lqEntry = matches.shift() ?? null;

  const lqQualifies = lqEntry?.status === 'within_limit';
  const eqCode = lqEntry?.eq_code ?? it.adr_data?.excepted_quantity ?? null;
  // EQ qualification is conservative: if eq_code is E1-E5 (numeric > 0), the
  // substance is *eligible* for EQ in principle. Per-package limit comparison
  // against the EQ code's table is out of scope for v1 — we report the code
  // and leave the per-package determination to the user.
  const eqEligible = !!eqCode && /^E[1-5]$/.test(eqCode);

  // Find the matching item in the exemption response by un_number
  const exItem = (exemptionResp.items || []).find((e) => e.un_number === it.un_number) ?? null;
  const tcPoints = exItem?.points ?? null;

  // Per-item warnings
  const reasons = [];
  if (it.adr_lookup_error) reasons.push(it.adr_lookup_error);
  if (lqEntry && lqEntry.status !== 'within_limit') reasons.push(`LQ ${lqEntry.status}: ${lqEntry.reason}`);

  return {
    input: {
      un_number: it.un_number,
      proper_shipping_name: it.proper_shipping_name,
      class: it.class,
      packing_group: it.packing_group,
      quantity_per_package: it.quantity_per_package,
      quantity_unit: it.quantity_unit,
      package_count: it.package_count,
      total_quantity: it.total_quantity,
      packaging_type: it.packaging_type,
      special_handling: it.special_handling,
    },
    adr_data: it.adr_data,
    lq_eq_check: {
      qualifies_for_lq: lqQualifies,
      qualifies_for_eq: eqEligible,
      max_lq: it.adr_data?.limited_quantity ?? null,
      max_eq: eqCode,
    },
    transport_category_points: tcPoints,
    _warnings: reasons,
  };
});

// Aggregate fields
const itemsWithWarnings = itemsOut
  .map((it, i) => (it._warnings.length ? { index: i, reasons: it._warnings } : null))
  .filter(Boolean);

const itemsWithErrors = itemsOut
  .map((it, i) => (!it.adr_data ? { index: i, reasons: ['UN not recognized'] } : null))
  .filter(Boolean);

// Strip _warnings from final items shape (kept it as scratch space)
for (const it of itemsOut) delete it._warnings;

// Tunnel restrictions: collect unique codes ordered by restrictiveness (most first)
const tunnelCodesSet = new Map();
for (const it of itemsOut) {
  const code = it.adr_data?.tunnel_restriction_code;
  if (code && code !== '(-)') tunnelCodesSet.set(code, tunnelRank(code));
}
const tunnelRestrictions = Array.from(tunnelCodesSet.entries())
  .sort((a, b) => b[1] - a[1])
  .map(([code]) => code);

// Exemption status
const totalPoints = exemptionResp.total_points ?? 0;
const hasCategoryZero = exemptionResp.has_category_zero ?? false;
const exemptionStatus = hasCategoryZero
  ? 'mixed_categories_check_required'
  : exemptionResp.exempt ? 'exempt' : 'exceeds_threshold';

// Driver ADR cert: required if exemption fails OR any item is TC 0 or 1
const driverCertRequired = !exemptionResp.exempt
  || itemsOut.some((it) => ['0', '1'].includes(String(it.adr_data?.transport_category ?? '')));

return [{
  json: {
    consignment,
    validation: {
      all_items_recognized: itemsWithErrors.length === 0,
      items_validated: itemsOut.length,
      items_with_warnings: itemsWithWarnings,
      items_with_errors: itemsWithErrors,
    },
    items: itemsOut,
    aggregate: {
      total_transport_category_points: totalPoints,
      exemption_113_6_status: exemptionStatus,
      vehicle_marking_required: !exemptionResp.exempt,
      tunnel_restrictions: tunnelRestrictions,
      driver_adr_certificate_required: driverCertRequired,
      notes: exemptionResp.warnings ?? [],
    },
  },
}];
